          <button onClick={() => setActiveTab("transcript")} style={menuItemStyle(activeTab === "transcript")}>📜 Transcript</button>
          <button onClick={() => setActiveTab("fee")} style={menuItemStyle(activeTab === "fee")}>💳 Fee Slip</button>
