};

const User = require("../models/user");
const Course = require("../models/course");

// Get all available courses
exports.getCourses = async (req, res) => {
  try {
    const courses = await Course.find();
    res.json({ courses }); // JSON object must contain 'courses' array
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

// Get all courses the student has registered
exports.getRegisteredCourses = async (req, res) => {
  try {
    const student = await User.findById(req.user.id).populate("registeredCourses");
    res.json({ registeredCourses: student.registeredCourses });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

// Register a course
exports.registerCourse = async (req, res) => {
  try {
    const course = await Course.findById(req.params.courseId);
    if (!course) return res.status(404).json({ message: "Course not found" });

    const student = await User.findById(req.user.id);
    if (!student.registeredCourses.includes(req.params.courseId)) {
      student.registeredCourses.push(req.params.courseId);
      await student.save();
    }

    res.json({ message: "Course registered", registeredCourses: student.registeredCourses });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

const jwt = require("jsonwebtoken");
const User = require("../models/user");

// Auth middleware
exports.authMiddleware = async (req, res, next) => {
  const token = req.headers.authorization?.split(" ")[1];
  if (!token) return res.status(401).json({ message: "No token provided" });

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET || "fallback_secret");
    const user = await User.findById(decoded.id);
    if (!user) return res.status(401).json({ message: "User not found" });

    req.user = user;
    next();
  } catch (err) {
    res.status(401).json({ message: "Invalid token" });
  }
};

// Admin/teacher middleware
exports.adminMiddleware = (req, res, next) => {
  if (req.user.role !== "admin" && req.user.role !== "teacher") {
    return res.status(403).json({ message: "Access denied. Admins/Teachers only." });
  }
  next();
};

const mongoose = require("mongoose");

const courseSchema = new mongoose.Schema({
  name: { type: String, required: true },
  instructor: { type: String, required: true },
  creditHours: { type: Number, required: true, min: 1 },
  feePerCredit: { type: Number, required: true, min: 0 },
});

module.exports = mongoose.model("Course", courseSchema);

const mongoose = require("mongoose");

const userSchema = new mongoose.Schema(
  {
    name: { type: String, required: true },
    email: { type: String, required: true, unique: true },
    password: { type: String, required: true },
    role: {
      type: String,
      enum: ["student", "teacher"],
      default: "student",
    },
    isApproved: {
      type: Boolean,
      default: false, // new users start as unapproved
    },
    registeredCourses: [
      {
        type: mongoose.Schema.Types.ObjectId,
        ref: "Course", // links to Course model
      },
    ],
  },
  { timestamps: true }
);

module.exports = mongoose.model("User", userSchema);

